import java.nio.file.*;
import java.io.IOException;

public class SecurePathTraversalExample {

    public static void main(String[] args) {
        String userInput = "../secretfile.txt";
        String directory = "/path/to/some/directory/";

        try {
            Path basePath = Paths.get(directory).normalize();
            Path userInputPath = Paths.get(userInput).normalize();
            Path resolvedPath = basePath.resolve(userInputPath);

            if (!resolvedPath.startsWith(basePath)) {
                System.out.println("Invalid path specified.");
                return;
            }

            byte[] fileContent = Files.readAllBytes(resolvedPath);
            System.out.println("File content: " + new String(fileContent));
        } catch (InvalidPathException e) {
            System.out.println("Invalid path specified.");
        } catch (IOException e) {
            System.out.println("An error occurred: " + e.getMessage());
        }
    }
}

